            .set(scope_attr, scope_val)
            .set(part_attr, part_val)
            .set(HtmlAttr::Id, self.ctx.ids.part("control"))
            .set(HtmlAttr::Role, "checkbox")
            .set(
                HtmlAttr::Aria(AriaAttr::Checked),
                aria_checked_token(*self.ctx.checked.get()),
